#include <stdio.h>
#include <stdlib.h>

int countGoodSubsequences(int* arr, int n, int m) {
    int count = 0;
    for (int mask = 1; mask < (1 << n); mask++) {
        int sum = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                sum += arr[i];
            }
        }
        if (sum % m == 0) {
            count++;
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T-- > 0) {
        int n, m;
        scanf("%d %d", &n, &m);
        int* arr = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", countGoodSubsequences(arr, n, m));
        free(arr);
    }
    return 0;
}

